import React from 'react'

import '../styles/cell.css'

export default class Cell extends React.Component {

    render() {
        return (
            <div
                className={"cell " + this.props.className}
                onClick={(e) => { this.props.onClick(e, this.props.cellId) }}
            >
            </div>
        )
    }
}


