import React from 'react'

import "../styles/score.css"

export default class Score extends React.Component {

    render() {

        return (
            <div className="score">

                <div>

                    <div className="score-progress-bar">
                        <div
                            className="computer-progress-bar"
                            style={{ width: this.props.computerScore / this.props.winningScore * 100 + '%' }}
                        ></div>
                    </div>

                    <div className="players-wrapper">
                        <div className="player">
                            <div>Computer</div>
                            <div className="count">{this.props.computerScore}</div>
                        </div>
                        <div className="player">
                            <div>You</div>
                            <div className="count">{this.props.humanScore}</div>
                        </div>
                    </div>


                    <div className="score-progress-bar">
                        <div
                            className="human-progress-bar"
                            style={{ width: this.props.humanScore / this.props.winningScore * 100 + '%' }}
                        ></div>
                    </div>
                </div>
            </div>
        )
    }

}



