import React, { Component } from 'react';
import Button from 'react-bootstrap/Button'


import '../styles/menu.css'


export default class Menu extends Component {

    constructor(props) {
        super(props)

        this.state = {
            cellHighlightInterval: this.props.cellHighlightInterval
        }
    }



    render() {
        return (
            <div className={this.props.show ? "menu-wrapper" : "menu-wrapper hidden"}>
                <div className="menu">
                    <div>
                        <span>Cell highlight timeout</span>
                        <input
                            type="number"
                            min="100"
                            max="10000"
                            step="50"
                            className="cell-highlight-timeout"
                            onChange={this.handleCellHighlightIntervalChange}
                            value={this.state.cellHighlightInterval}
                        />
                        <span>ms</span>
                    </div>

                    <Button
                        className="start-button"
                        onClick={(e) => { this.props.startButtonClick(e, this.state.cellHighlightInterval) }}
                    >
                        Start
                    </Button>
                </div>
            </div>
        )
    }



    handleCellHighlightIntervalChange = (e) => {

        this.setState({
            cellHighlightInterval: e.target.value
        })
    }


}


