import React from 'react'

import Cell from './Cell'

import '../styles/field.css'

export default class Field extends React.Component {

    render() {

        return (
            <div className="field">
                {this.generateCells()}
            </div>
        )
    }


    generateCells() {

        const cells = []

        for (let i = 0; i < this.props.cellCount; i++) {
            cells.push(
                <Cell
                    key={i}
                    cellId={i}
                    className={this.determineClassName(i)}
                    onClick={this.props.cellClick}
                />)

        }

        return cells;
    }



    determineClassName(cellIndex) {
        if (cellIndex !== this.props.highlitedCell)
            return ''
        else {
            if (this.props.isWin)
                return 'win'
            if (this.props.isLoose)
                return 'loose'
            return 'highlited'
        }
    }
}


