
import React from 'react'
import Modal from 'react-bootstrap/Modal'


export default class WinModal extends React.Component {

    constructor() {
        super()

        this.state = {
            show: false
        }
    }



    render() {

        if (this.props.show) {

            let modalHeader = ''
            let modalDescription = ''

            if (this.props.winner === 'human') {
                modalHeader = 'You won!'
                modalDescription = 'That was a good one! Machines are already crying!'
            }
            else {
                modalHeader = 'Computer won!'
                modalDescription = 'Well, not this time... You can always try one more time! If you not scared, of cource.'
            }

            return (
                <Modal show={true} onHide={this.props.onHide}>

                    <Modal.Header closeButton>
                        <Modal.Title>{modalHeader}</Modal.Title>
                    </Modal.Header>

                    <Modal.Body>
                        {modalDescription}
                    </Modal.Body>

                </Modal>
            )
        }
        else {
            return <div></div>
        }
    }
}



