import React, { Component } from 'react';

import Field from './components/Field'
import Score from './components/Score'
import WinModal from './components/WinModal'
import Menu from './components/Menu'

import 'bootstrap/dist/css/bootstrap.min.css';

import './styles/game.css'

export default class Game extends Component {

    constructor() {

        super()

        this.state = {
            cellCount: 100,
            cellHighlightInterval: 900,
            winOrLooseHighlightInterval: 900,
            breakTimeout: 500,
            winningScore: 10,
            computerScore: 0,
            humanScore: 0,
            highlitedCell: null,
            isRoundLoose: false,
            isRoundWin: false,
            isGameStarted: false,
            showModal: false,
            winner: ''
        }

        this.highliteTimeout = {}

    }



    render() {

        return (
            <div className="game">
                <div>
                    <Menu
                        show={!this.state.isGameStarted}
                        cellHighlightInterval={this.state.cellHighlightInterval}
                        startButtonClick={this.handleStartButtonClick}
                    />
                    <WinModal
                        show={this.state.showModal}
                        winner={this.state.winner}
                        onHide={this.handleModalHide}
                    />
                    <Score
                        winningScore={this.state.winningScore}
                        humanScore={this.state.humanScore}
                        computerScore={this.state.computerScore}
                    />

                    <Field
                        cellCount={this.state.cellCount}
                        cellClick={this.handleCellClick}
                        isLoose={this.state.isRoundLoose}
                        isWin={this.state.isRoundWin}
                        highlitedCell={this.state.highlitedCell}
                    />
                </div>
            </div>
        );
    }



    handleStartButtonClick = (e, cellHighlightInterval) => {

        let interval = parseInt(cellHighlightInterval, 10);

        if (!interval || interval < 100 || interval > 10000)
            interval = this.state.cellHighlightInterval

        this.startGame(interval)

    }



    handleCellClick = (e, cellId) => {

        if (cellId === this.state.highlitedCell) {

            this.roundWin()

        }

    }



    handleModalHide = () => {
        this.stopGame()
    }



    startGame(cellHighlightInterval) {

        this.setState({
            cellHighlightInterval,
            isGameStarted: true
        }, this.gameIteration)

    }



    stopGame() {
        this.setState({
            computerScore: 0,
            humanScore: 0,
            highlitedCell: null,
            isRoundLoose: false,
            isRoundWin: false,
            isGameStarted: false,
            showModal: false,
            winner: ''
        })
    }



    gameIteration() {

        const highlitedCellId = Math.floor(Math.random() * this.state.cellCount)

        this.interval(this.state.breakTimeout)
            .then(() => this.higlightCell(highlitedCellId))
            .then(() => this.interval(this.state.cellHighlightInterval))
            .then(() => this.checkForRoundLoose())
            .then(() => this.shouldContinueGame()) // this promise gets rejected if someone wins
            .then(() => this.interval(this.state.winOrLooseHighlightInterval))
            .then(() => this.clearRoundInfo())
            .then(() => this.gameIteration())
            .catch(winner => this.showModalWindow(winner))
    }



    interval(time) {

        return new Promise((resolve, reject) => {

            this.highliteTimeout = setTimeout(() => {
                resolve()
            }, time)

        })

    }



    higlightCell(highlitedCellId) {

        return new Promise((resolve, reject) => {

            this.setState({
                highlitedCell: highlitedCellId
            }, resolve)

        })

    }


    checkForRoundLoose() {

        return new Promise((resolve, reject) => {

            if (!this.state.isRoundWin) {
                this.roundLoose()
                    .then(resolve)
            }
            else {
                resolve()
            }

        })

    }


    shouldContinueGame() {

        return new Promise((resolve, reject) => {

            if (this.state.humanScore === this.state.winningScore)
                reject('human')
            else if (this.state.computerScore === this.state.winningScore)
                reject('computer')
            else
                resolve()
        })

    }



    showModalWindow(winner) {
        this.setState({
            showModal: true,
            winner
        })
    }



    clearRoundInfo() {

        return new Promise((resolve, reject) => {

            this.setState({
                isRoundWin: false,
                isRoundLoose: false,
                highlitedCell: null
            }, resolve)
        })
    }



    roundWin() {

        if (this.state.isRoundLoose || this.state.isRoundWin)
            return

        clearTimeout(this.highliteTimeout) // timout clear is used to stop cell highlighting

        this.setState((state, props) => ({
            humanScore: state.humanScore + 1,
            isRoundWin: true
        }), () => {
            this.shouldContinueGame() // this promise gets rejected if someone wins
                .then(() => this.interval(this.state.winOrLooseHighlightInterval))
                .then(() => this.clearRoundInfo())
                .then(() => this.gameIteration())
                .catch(winner => this.showModalWindow(winner))
        })
    }



    roundLoose() {

        return new Promise((resolve, reject) => {

            this.setState((state, props) => ({

                computerScore: state.computerScore + 1,
                isRoundLoose: true

            }), resolve)

        })

    }

}


